// Parsear información del nombre del archivo
const items = $input.all();

function lastMatch(text, re) {
  let m, last = null;
  while ((m = re.exec(text)) !== null) last = m;
  return last;
}

function normAmPm(s) {
  if (!s) return null;
  const t = s.toLowerCase().replace(/\./g, "");
  if (t === "am") return "AM";
  if (t === "pm") return "PM";
  return null;
}

function parseFromFileName(fileName) {
  const extension = (fileName.split(".").pop() || "").toLowerCase();
  const stem = fileName.replace(/\.[^.]+$/, "");

  const dateRE = /(\d{4}-\d{2}-\d{2})/g;
  const dm = lastMatch(stem, dateRE);
  const fecha = dm ? dm[1] : null;

  const timeRE = /(\d{1,2})([.:])(\d{2})(?:\2(\d{2}))?\s*(a\.?m|p\.?m|am|pm)?/gi;
  const tm = lastMatch(stem, timeRE);

  let hora = null;
  if (tm) {
    let hh = tm[1].padStart(2, "0");
    const mm = tm[3];
    const ss = tm[4] || "00";
    const ampm = normAmPm(tm[5]);

    if (ampm) {
      hora = `${hh}:${mm}:${ss} ${ampm}`;
    } else {
      hora = `${hh}:${mm}:${ss}`;
    }
  }

  let ejecutivo = stem;
  if (fecha) ejecutivo = ejecutivo.replace(fecha, " ");
  if (tm) ejecutivo = ejecutivo.replace(tm[0], " ");
  ejecutivo = ejecutivo.replace(/\ba\s+las\b/i, " ");
  ejecutivo = ejecutivo.replace(/\s{2,}/g, " ").trim();

  return { extension, fecha, hora, ejecutivo };
}

return items.map(item => {
  const fileName = item.json.name;
  const fileId = item.json.id;
  const { extension, fecha, hora, ejecutivo } = parseFromFileName(fileName);

  return {
    json: {
      fileId,
      fileName,
      extension,
      ejecutivo,
      fecha,
      hora,
      mimeType: item.json.mimeType
    }
  };
});

// Combinar datos de todos los nodos anteriores para tenerlos disponibles
const idx = $itemIndex;

// Datos del parseo de nombre
const metaItems = $items('Parsear nombre archivo');
const meta = metaItems[idx]?.json || {};

// Datos de la transcripción
const transItems = $items('Transcribir audio');
const transcript = transItems[idx]?.json?.text || '';

// Datos del análisis de KPIs
const currentJson = $json;

return {
  // Metadata del archivo
  fileId: meta.fileId,
  fileName: meta.fileName,
  ejecutivo: meta.ejecutivo,
  fecha: meta.fecha,
  hora: meta.hora,

  // Transcripción
  transcript: transcript,

  // Análisis KPI (viene del nodo actual)
  kpiAnalysis: currentJson,

  itemIndex: idx
};

// Preparar datos para actualizar el Sheet
const idx = $itemIndex;

// Obtener el ID del sheet copiado (viene del nodo actual - Copiar plantilla)
const sheetId = $json.id;

// Obtener datos combinados del nodo anterior
const combineItems = $items('Combinar datos');
const combined = combineItems[idx]?.json || {};

const ejecutivo = combined.ejecutivo || '';
const fechaLlamada = combined.fecha || '';
const fechaMonitoreo = new Date().toISOString().slice(0,10);
const transcript = combined.transcript || '';
const audioFileId = combined.fileId || '';

// Extraer KPIs del análisis
const ai = combined.kpiAnalysis || {};
let kpi = {};
let observaciones = '';
let resumen = '';

try {
  if (ai.kpi) {
    kpi = ai.kpi;
  } else if (ai.message?.content?.kpi) {
    kpi = ai.message.content.kpi;
  }

  observaciones = ai.observaciones || ai.message?.content?.observaciones || '';
  resumen = ai.resumen_ejecutivo || ai.message?.content?.resumen_ejecutivo || '';
} catch (e) {
  console.error('Error extrayendo KPIs:', e);
}

// Función para convertir a booleano
function toBool(v) {
  if (v === true || v === 'true') return true;
  if (v === false || v === 'false') return false;
  return null;
}

// Función para encontrar key de KPI por número
function findKpiKey(kpiObj, num) {
  const keys = Object.keys(kpiObj || {});
  const pattern = new RegExp('^' + num + '(?:[_\\-\\s]|$)');
  return keys.find(k => pattern.test(k));
}

const TAB = 'Hoja 1';
const updates = [];

// Encabezados
if (ejecutivo) {
  updates.push({ range: TAB + '!B6', values: [[ejecutivo]] });
}
if (fechaLlamada) {
  updates.push({ range: TAB + '!G5', values: [[fechaLlamada]] });
}
updates.push({ range: TAB + '!G6', values: [[fechaMonitoreo]] });

// KPIs (E9:F29)
const START = 9;
const ROWS = 21;
const siCol = Array.from({ length: ROWS }, () => ['']);
const noCol = Array.from({ length: ROWS }, () => ['']);

for (let i = 1; i <= 20; i++) {
  const rowIdx = i <= 10 ? (i - 1) : i;
  if (rowIdx === 10) continue;

  const key = findKpiKey(kpi, i);
  const val = toBool(key ? kpi[key] : undefined);

  if (val === true) siCol[rowIdx][0] = 'SI';
  if (val === false) noCol[rowIdx][0] = 'NO';
}

updates.push({ range: TAB + '!E' + START + ':E29', values: siCol });
updates.push({ range: TAB + '!F' + START + ':F29', values: noCol });

// Detalle (resumen o transcripción)
const detalle = (resumen && resumen.trim()) ? resumen : transcript;
if (detalle.trim()) {
  updates.push({ range: TAB + '!B43', values: [[detalle.slice(0, 49000)]] });
}

// Observaciones
if (observaciones.trim()) {
  updates.push({ range: TAB + '!D43', values: [[observaciones.slice(0, 49000)]] });
}

return {
  sheetId: sheetId,
  audioFileId: audioFileId,
  valueInputOption: 'USER_ENTERED',
  data: updates,
  itemIndex: idx
};

// Preservar IDs para los siguientes nodos
const idx = $itemIndex;

const prepareItems = $items('Preparar datos Sheet');
const prepData = prepareItems[idx]?.json || {};

return {
  sheetId: prepData.sheetId,
  audioFileId: prepData.audioFileId,
  itemIndex: idx
};
